    [InlineData(null, "This SqlTransaction has completed; it is no longer usable", true)]
    [InlineData("Some message with Execution Timeout Expired inside", null, true)]
    [InlineData(null, "prefix Microsoft.Data.SqlClient.SqlException suffix", true)]
    public void IsTransientError_ReturnsTrue_WhenKeywordPresent(
        string? reportDataTransMessage,
        string? pdfGenMessage,
        bool expected)
    {
        var result = FailedCtrService.IsTransientError(reportDataTransMessage, pdfGenMessage);
        Assert.Equal(expected, result);
