    [Theory]
    [InlineData("Success", "Success", false)]
    [InlineData(null, null, false)]
    [InlineData("", "", false)]
    [InlineData("UnexpectedFailure", "UnexpectedFailure", false)]
    [InlineData("Some random error message", "Another random message", false)]
    public void IsTransientError_ReturnsFalse_WhenNoKeywordPresent(
        string? reportDataTransMessage,
        string? pdfGenMessage,
        bool expected)
    {
        var result = FailedCtrService.IsTransientError(reportDataTransMessage, pdfGenMessage);
        Assert.Equal(expected, result);
